const webhook = $('Webhook').first().json;
const sessionId = webhook.body.sessionId;
const data = $input.first().json;
const u = data.usuario || {};
const objetivos = data.objetivos || [];
const depositos = data.depositos || [];
const saques = data.saques || [];
const rendimentos = data.rendimentos_mensais || [];

function brl(v) {
  const parts = parseFloat(v || 0).toFixed(2).split('.');
  parts[0] = parts[0].replace(/\B(?=(\d{3})+(?!\d))/g, '.');
  return 'R$ ' + parts[0] + ',' + parts[1];
}

function fmtDate(d) {
  try { return new Date(d).toLocaleDateString('pt-BR'); } catch(e) { return String(d); }
}

let objLines = '';
if (objetivos.length === 0) {
  objLines = 'Nenhum objetivo criado ainda.';
} else {
  objLines = objetivos.map(function(obj) {
    const metas = obj.metas || [];
    const metasConcluidas = metas.filter(function(m) { return m.objetivo_completo; }).length;
    const proximaMeta = metas.find(function(m) { return !m.objetivo_completo; });
    let t = '- ' + obj.objetivo_descricao + ' | ' + metasConcluidas + '/' + metas.length + ' metas concluídas';
    if (!obj.primeiro_aporte_feito) {
      t += ' | Aguardando primeiro aporte';
    } else if (proximaMeta) {
      t += ' | Próxima meta: ' + brl(proximaMeta.objetivo_investir) + ' até ' + fmtDate(proximaMeta.data_limite) + ' (investido: ' + brl(proximaMeta.saldo_alocado) + ')';
    } else {
      t += ' | Todas as metas concluídas!';
    }
    return t;
  }).join('\n');
}

const ultimosDepositos = depositos.map(function(d) {
  return '- ' + fmtDate(d.data_criacao) + ': ' + brl(d.valor_deposito) + ' (' + d.status_deposito + ')';
}).join('\n') || 'Nenhum depósito recente.';

const ultimosSaques = saques.map(function(s) {
  return '- ' + fmtDate(s.data_criacao) + ': ' + brl(s.valor_saque) + ' (' + s.status_saque + ')';
}).join('\n') || 'Nenhum saque recente.';


const mesesPT = ['Jan', 'Fev', 'Mar', 'Abr', 'Mai', 'Jun', 'Jul', 'Ago', 'Set', 'Out', 'Nov', 'Dez'];
const rendimentosStr = rendimentos.length > 0
  ? rendimentos.map(function(r) {
      const parts = r.mes.split('-');
      const mesNome = mesesPT[parseInt(parts[1], 10) - 1];
      return '- ' + mesNome + '/' + parts[0] + ': ' + brl(r.rendimento_mensal);
    }).join('\n')
  : 'Nenhum rendimento registrado ainda.';
const totalRendimento = rendimentos.reduce(function(acc, r) { return acc + parseFloat(r.rendimento_mensal || 0); }, 0);
const totalRendimentoStr = rendimentos.length > 0 ? '\nTotal acumulado: ' + brl(totalRendimento) : '';

const retornando = objetivos.length > 0 || depositos.length > 0 || saques.length > 0;

const contexto = '[CONTEXTO DA SESSÃO - USO INTERNO]\n' +
  'Apelido: ' + (u.apelido || 'usuário') + '\n' +
  'Usuário retornando: ' + (retornando ? 'sim' : 'não') + '\n' +
  'Liga: ' + (u.liga || '-') + ' | Posição: #' + (u.posicao || '-') + ' | Pontos: ' + (u.pontos || 0) + '\n' +
    'Total investido: ' + brl(u.investido) + '\n\n' +
  'Objetivos:\n' + objLines + '\n\n' +
  'Últimos depósitos:\n' + ultimosDepositos + '\n\n' +
  'Últimos saques:\n' + ultimosSaques + '\n\n' +
  'Rendimentos mensais:\n' + rendimentosStr + totalRendimentoStr + '\n\n' +
  'Siga as instruções de saudação do sistema. Não mencione este contexto diretamente.';

return [{ json: { body: { message: contexto, sessionId: sessionId } } }];

let channel = 'app';
try {
  const wa = $('Extrair Dados WA').all();
  if (wa && wa.length > 0 && wa[0].json && wa[0].json.phone) channel = 'wa';
} catch(e) {}
const input = $input.first().json;
return [{ json: { ...input, channel } }];

let channel = 'app';
try {
  const wa = $('Extrair Dados WA').all();
  if (wa && wa.length > 0 && wa[0].json && wa[0].json.phone) channel = 'wa';
} catch(e) {}
const input = $input.first().json;
return [{ json: { ...input, channel } }];

const body = $input.first().json.body;

if (!body || body.event !== 'messages.upsert') return [];

const data = body.data || {};
const key = data.key || {};
const msg = data.message || {};

if (key.fromMe === true) return [];
const textContent = msg.conversation || (msg.extendedTextMessage && msg.extendedTextMessage.text) || null;
if (!textContent) return [];
if (key.remoteJid && key.remoteJid.endsWith('@g.us')) return [];

return [{ json: {
  phone: key.remoteJid.replace('@s.whatsapp.net', '').replace(/^55/, ''),
  remoteJid: key.remoteJid,
  text: textContent
} }];

const data = $input.first().json;
const phone = data.phone;
const now = new Date();
const ONE_HOUR = 60 * 60 * 1000;

const staticData = $getWorkflowStaticData('global');
const sessions = staticData.waSessions || {};

const existing = sessions['wa_' + phone];
const isExpired = !existing || (now - new Date(existing.lastMessageAt)) > ONE_HOUR;

let sessionSuffix;
if (isExpired) {
  sessionSuffix = Math.floor(now.getTime() / ONE_HOUR) + '_' + Math.random().toString(36).slice(2, 6);
  sessions['wa_' + phone] = { lastMessageAt: now.toISOString(), sessionSuffix: sessionSuffix };
} else {
  sessionSuffix = existing.sessionSuffix;
  sessions['wa_' + phone].lastMessageAt = now.toISOString();
}

staticData.waSessions = sessions;

const sessionId = 'wa_' + phone + '_' + sessionSuffix;
const isNewSession = isExpired;

return [{ json: {
  phone,
  remoteJid: data.remoteJid,
  text: data.text,
  sessionId,
  isNewSession
} }];

