}

const norm = text.trim().toLowerCase();
const isSim    = /^(1|sim|yes|quero|pode|claro|ok|confirmar?|fa[cç]a?)(\s|$)/i.test(norm);
const isNao    = /^(2|outro|outra|diferente|muda)/.test(norm);
const isCancel = /^(3|cancel|cancelar|sair|parar|desistir|n[aã]o|nao)/.test(norm);

const confirmMsg = 'Quer fazer o depósito de ' + brl(depositValue) + '?\n\nDigite:\n\n*1* - para confirmar\n*2* - para escolher outro valor\n*3* - para cancelar';

