    delete sessions['wa_' + phone].depositStep;
    delete sessions['wa_' + phone].depositValue;
    output = 'Tudo bem, cancelei o depósito.\n\nComo mais posso te ajudar?\n\n- Seus *objetivos* \n- Suas *metas*\n- Seus *depósitos*\n- Seus *saques*\n- Sua posição no *ranking*\n- Sua *pontuação*\n- Quanto você já tem *investido*\n- Qual o seu *rendimento*\n- Fazer um depósito *Pix*\n\nQual desses você quer saber?';
  } else if (isNao) {
    sessions['wa_' + phone].depositStep = 'ask_custom';
    output = 'Tudo bem!\n\nQual valor você quer depositar?';
  } else {
    output = confirmMsg;
  }
} else if (depositStep === 'ask_custom') {
  if (isCancel) {
    delete sessions['wa_' + phone].depositStep;
    delete sessions['wa_' + phone].depositValue;
    output = 'Tudo bem, cancelei o depósito.\n\nComo mais posso te ajudar?\n\n- Seus *objetivos* \n- Suas *metas*\n- Seus *depósitos*\n- Seus *saques*\n- Sua posição no *ranking*\n- Sua *pontuação*\n- Quanto você já tem *investido*\n- Qual o seu *rendimento*\n- Fazer um depósito *Pix*\n\nQual desses você quer saber?';
  } else {
    const clean = text.replace(/r\$\s*/i, '').replace(/\./g, '').replace(',', '.');
    const match = clean.match(/(\d+(?:\.\d{1,2})?)/);
    if (match && parseFloat(match[1]) >= 1) {
