      callPix = true;
      delete sessions['wa_' + phone].depositStep;
      delete sessions['wa_' + phone].depositValue;
    } else {
      output = 'Não entendi o valor.\n\nMe diz quanto quer depositar. Exemplo: 50,00\n\nOu digite *3* para cancelar.';
    }
  }
}

staticData.waSessions = sessions;

if (callPix) {
